<template>
  <view class="page-container">
    <!-- 筛选 -->
    <view class="filter-box">
      <u-button size="mini" plain @click="showCategoryPicker = true">
        {{ diseaseLabel }} <u-icon name="arrow-down" size="12"></u-icon>
      </u-button>
      <u-button size="mini" plain @click="resetFilters">
        重置
      </u-button>
    </view>

    <!-- 列表 -->
    <view class="list-box">
      <u-cell-group>
        <u-cell
          v-for="item in list"
          :key="item.id"
          :title="item.title"
          :label="item.org + ' · ' + item.year"
          is-link
          @click="open(item)"
        >
          <template #value>
            <u-tag text="官方" type="primary" size="mini"></u-tag>
          </template>
        </u-cell>
      </u-cell-group>

      <!-- 空状态 -->
      <u-empty 
        v-if="!loading && list.length === 0" 
        mode="data" 
        description="暂无指南数据"
      ></u-empty>

      <!-- 加载状态 -->
      <view v-if="loading" class="loading-state">
        <u-loading-icon mode="circle"></u-loading-icon>
      </view>
    </view>

    <!-- 分类/疾病选择弹窗 (使用 u-picker 级联或分步选择) -->
    <!-- 这里为了简化，使用两个独立的 picker，逻辑保持与原代码一致 -->
    
    <!-- 第一步：选择大类 (Category) -->
    <u-picker
      :show="showCategoryPicker"
      :columns="[categoryOptions]"
      keyName="text"
      @confirm="onCategoryConfirm"
      @cancel="showCategoryPicker = false"
      @close="showCategoryPicker = false"
    ></u-picker>

    <!-- 第二步：选择具体疾病 (Disease) -->
    <u-picker
      :show="showDiseasePicker"
      :columns="[diseaseOptions]"
      keyName="text"
      @confirm="onDiseaseConfirm"
      @cancel="showDiseasePicker = false"
      @close="showDiseasePicker = false"
    ></u-picker>
  </view>
</template>

<script setup lang="ts">
import { ref, computed, onMounted, watch } from 'vue'
import request from '@/utils/request'

// 类型定义
interface GuideItem {
  id: number
  title: string
  org: string
  year: string
  summary?: string
  pdfUrl?: string
}

// 响应式数据
const categoryId = ref<number | null>(null)
const diseaseId = ref<number | null>(null)
const categoryOptions = ref<{ text: string; value: number; children: { text: string; value: number }[] }[]>([])
const diseaseOptions = ref<{ text: string; value: number | null }[]>([])
const list = ref<GuideItem[]>([])
const loading = ref<boolean>(false)

// 弹窗控制
const showCategoryPicker = ref(false)
const showDiseasePicker = ref(false)

// 计算显示标签
const diseaseLabel = computed(() => {
  const category = categoryOptions.value.find(c => c.value === categoryId.value)
  const disease = diseaseOptions.value.find(d => d.value === diseaseId.value)
  
  if (!category) return '请选择疾病'
  if (!disease || diseaseId.value === null) return `${category.text} - 全部`
  
  return `${category.text} - ${disease.text}`
})

// 获取分类及疾病数据
// GuideList.vue <script setup>

// 获取分类及疾病数据
const fetchCategoryOptions = async () => {
  try {
    const res = await request.get('/api/knowledge/disease-tree')
    // 【修改点】增加空值判断，防止 res.data 为 null
    const categories = res?.data || [] 
    
    return categories.map((category: any) => ({
      text: category.name,
      value: category.id,
      children: (category.children || []).map((disease: any) => ({
        text: disease.name,
        value: disease.id
      }))
    }))
  } catch (error) {
    uni.__f__('error','at pages/resource/medical/GuideList.vue:124','获取分类数据失败:', error)
    return []
  }
}

// 确认分类（第一级）
const onCategoryConfirm = (e: any) => {
  const selected = e.value[0]
  categoryId.value = selected.value
  diseaseId.value = null

  // 动态生成疾病选项，插入"全部疾病"
  const children = selected.children || []
  diseaseOptions.value = [
    { text: '全部疾病', value: null },
    ...children.map((disease: any) => ({
      text: disease.text,
      value: disease.value
    }))
  ]

  showCategoryPicker.value = false
  // 自动弹出第二级选择，或者让用户手动点击？原逻辑是自动弹出 showDisease = true
  showDiseasePicker.value = true
}

// 确认疾病（第二级）
const onDiseaseConfirm = (e: any) => {
  const selected = e.value[0]
  diseaseId.value = selected.value === null ? null : selected.value
  showDiseasePicker.value = false
}

// 加载指南列表
const loadGuideList = async () => {
  loading.value = true
  try {
    const res = await request.get('/api/resource/medical/guides', {
      params: { disease: diseaseId.value, page: 1, pageSize: 20 }
    })
    list.value = res.data.list || []
  } catch (error) {
    uni.__f__('error','at pages/resource/medical/GuideList.vue:166','加载指南列表失败:', error)
    uni.showToast({ title: '加载失败', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 重置筛选条件
const resetFilters = () => {
  categoryId.value = null
  diseaseId.value = null
  diseaseOptions.value = []
  // 注意：重置后可能需要重新选择分类，或者显示“请选择疾病”
}

// 监听筛选条件变化，重新加载列表
watch([categoryId, diseaseId], () => {
  // 只有当 diseaseId 变化时才加载，避免选择 Category 时触发两次（一次是清空，一次是赋值）
  // 或者简单处理：只要 diseaseId 变了就加载
  if (categoryId.value !== null) { 
     loadGuideList()
  }
})

// 打开详情页
const open = (item: GuideItem) => {
  uni.navigateTo({
    url: `/pages/resource/medical/GuideDetail?id=${item.id}`
  })
}

// 生命周期
onMounted(async () => {
  categoryOptions.value = await fetchCategoryOptions()
  loadGuideList()
})
</script>

<style scoped>
.page-container {
  min-height: 100vh;
  background-color: #f9fafb;
  padding: 16px;
}

.filter-box {
  display: flex;
  gap: 8px;
  margin-bottom: 12px;
}

.list-box {
  /* 列表样式 */
}

.loading-state {
  display: flex;
  justify-content: center;
  padding: 16px 0;
}
</style>